import { describe, it, expect } from "vitest";
import { execSync } from "child_process";

const claimOffice = (input: string): string => {
  return execSync("tsx src/cli.ts", { input, encoding: "utf-8" });
};

describe("claim-office CLI", () => {
  // ============================================
  // BASE CASES - Empty and simplest scenarios
  // ============================================

  it.todo("empty item list quote -> premium 5 G (only processing fee)");

  // ============================================
  // ITEM VALUES AND BASE PREMIUMS
  // ============================================

  it.todo("single sword quote -> premium 105 G (100 base + 5 fee)");
  it.todo("single amulet quote -> premium 65 G (60 base + 5 fee)");
  it.todo("single staff quote -> premium 85 G (80 base + 5 fee)");
  it.todo("single potion quote -> premium 45 G (40 base + 5 fee)");
  it.todo("single rune quote -> premium 30 G (25 base + 5 fee)");
  it.todo("single moonstone quote -> premium 30 G (25 base + 5 fee)");

  // ============================================
  // COMPONENT BLOCKS (3 alike components)
  // ============================================

  it.todo("2 runes quote -> premium 55 G (2×25 base + 5 fee = 50+5)");
  it.todo("3 runes quote -> premium 65 G (60 block base + 5 fee)");
  it.todo("4 runes quote -> premium 105 G (4×25 base + 5 fee = 100+5)");
  it.todo("7 runes quote -> premium 180 G (7×25 base + 5 fee = 175+5)");
  it.todo("2 runes + 1 moonstone quote -> premium 80 G (2×25 + 25 + 5 = 75+5)");
  it.todo("3 runes + 3 moonstones quote -> premium 125 G (60 + 60 + 5 = 120+5)");

  // ============================================
  // PREMIUM MODIFIERS - Item-specific
  // ============================================

  it.todo("cursed sword quote -> premium 158 G (100 base + 50 cursed + 5 fee = 155, rounded up)");
  it.todo("sword with enchantment 5 quote -> premium 136 G (100 base + 30 high-enchant + 5 fee = 135+5)");
  it.todo("sword with enchantment 4 quote -> premium 105 G (no high-enchant surcharge)");
  it.todo("cursed sword with enchantment 5 quote -> premium 193 G (100 + 50 + 30 + 5 = 185, rounded up from 185.0)");
  it.todo("cursed sword with enchantment 4 quote -> premium 158 G (100 + 50 + 5 = 155, rounded up)");

  // ============================================
  // PREMIUM MODIFIERS - Policy-wide
  // ============================================

  it.todo("customer with 2 years loyalty quote -> premium 84 G (100 base - 20 loyalty + 5 fee = 85-1=84, 100*0.8=80+5=85, rounded down from 85.0)");
  it.todo("customer with 3 years loyalty, first insurance quote -> premium 104 G (100 + 10 first - 20 loyalty + 5 = 95, rounded up)");
  it.todo("customer with 3 years loyalty, second contract quote -> premium 81 G (100 + 10 first - 20 loyalty - 15 follow-up + 5 = 80, rounded up)");

  // ============================================
  // MODIFIER SCOPE - Multi-item policies
  // ============================================

  it.todo("cursed sword + plain amulet quote -> premium 215 G (100+60 base + 50 cursed on sword only + 5 fee = 215)");

  // ============================================
  // ROUNDING IN MHPCO'S FAVOR
  // ============================================

  it.todo("premium calculation yields 197.5 G -> final premium 198 G (rounded up)");
  it.todo("payout calculation yields 350.5 G -> final payout 350 G (rounded down)");

  // ============================================
  // INTEGRATION EXAMPLES - Quote
  // ============================================

  it.todo("newcomer with cursed sword (0 years, no previous) -> premium 165 G (100 + 50 cursed + 10 first + 5 fee)");
  it.todo("long-standing customer's second contract with cursed sword (3 years, second quote, enchantment 7) -> premium 160 G (100 + 50 cursed + 30 high-enchant - 20 loyalty + 10 first - 15 follow-up + 5 = 155+5)");

  // ============================================
  // CLAIM PROCESSING - Base cases
  // ============================================

  it.todo("claim: regular sword damage 500 G -> payout 400 G (500 - 100 deductible)");
  it.todo("claim: rune damage 200 G -> payout 100 G (200 - 100 deductible)");

  // ============================================
  // CLAIM PROCESSING - Special clauses
  // ============================================

  it.todo("claim: dragon-material sword, enchantment 9, damage 1000 G -> payout 400 G (50% of 1000 = 500 - 100 deductible)");
  it.todo("claim: dragon-material sword, enchantment 5, damage 800 G -> payout 700 G (800 - 100 deductible, full reimbursement)");
  it.todo("claim: steel sword, enchantment 9, damage 1000 G -> payout 400 G (50% of 1000 = 500 - 100 deductible)");
  it.todo("claim: dragon-material sword, enchantment 8, damage 1000 G -> payout 400 G (50% of 1000 = 500 - 100 deductible)");

  // ============================================
  // CLAIM PROCESSING - Deductible per damage event
  // ============================================

  it.todo("claim: dragon attack damages sword (500 G) and amulet (300 G) -> payout 600 G (500-100 + 300-100 = 400+200)");

  // ============================================
  // CLAIM PROCESSING - Cap
  // ============================================

  it.todo("claim: sword policy (insurance sum 1000 G, cap 2000 G), damage 1500 G -> payout 1400 G, remainingCap 600 G");
  it.todo("claim: sword policy after first claim (cap remaining 600 G), second damage 1500 G -> payout 600 G, remainingCap 0 G");
  it.todo("claim: sword + amulet policy (insurance sum 1600 G, cap 3200 G) -> cap is 3200 G");
  it.todo("claim: cursed sword policy (insurance value 1000 G) -> cap 2000 G (modifiers don't raise cap)");
  it.todo("claim: sword + 3 runes (block) policy -> insurance sum 1750 G (1000 + 3×250), cap 3500 G");

  // ============================================
  // CLAIM PROCESSING - Multiple items of same type
  // ============================================

  it.todo("claim: two swords policy, both damaged -> payout 800 G (2×(500-100) for 500 damage each)");

  // ============================================
  // EDGE CASES - Error conditions
  // ============================================

  it.todo("quote with unknown item type -> exits with non-zero status, error to stderr");
  it.todo("claim with damage entry for item not in policy -> exits with non-zero status, error to stderr");
  it.todo("claim with damage entry with negative amount -> exits with non-zero status, error to stderr");
  it.todo("claim with more damage entries of a type than policy covers -> exits with non-zero status, error to stderr");

  // ============================================
  // MODIFIER THRESHOLDS
  // ============================================

  it.todo("customer with exactly 2 years -> loyalty discount applies");
  it.todo("sword with exactly enchantment 5 -> high-enchantment surcharge applies");
  it.todo("sword with exactly enchantment 8, dragon material, damage 1000 G -> payout 400 G (50% rule then deductible)");

  // ============================================
  // ENCHANTMENT THRESHOLD VS DRAGON MATERIAL
  // ============================================

  it.todo("claim: dragon-material sword, enchantment 9, damage 1000 G -> payout 400 G (50% wins over full)");
  it.todo("claim: dragon-material sword, enchantment 5, damage 800 G -> payout 700 G (full reimbursement wins)");
  it.todo("claim: steel sword, enchantment 9, damage 1000 G -> payout 400 G (50% applies)");

  // ============================================
  // MULTI-STEP SCENARIOS
  // ============================================

  it.todo("multi-step: quote then claim against that policy");
  it.todo("multi-step: two quotes then claim against first policy");
  it.todo("multi-step: quote, claim, claim again (cap exhaustion)");
});

