input.newString:
import { readFileSync } from "fs";

const input = readFileSync(0, "utf-8");
const scenario = JSON.parse(input);

const basePremiums: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const results = scenario.steps.map((step: any) => {
  if (step.op === "quote") {
    const base = step.items.reduce((sum: number, item: any) => {
      return sum + (basePremiums[item.type] || 0);
    }, 0);
    return { premium: base + 5 };
  }
  return { premium: 5 };
});

