input.newString:
import { readFileSync } from "fs";

const input = readFileSync(0, "utf-8");
const scenario = JSON.parse(input);

const basePremiums: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const componentTypes = new Set(["rune", "moonstone"]);

const results = scenario.steps.map((step: any) => {
  if (step.op === "quote") {
    const items = step.items as Array<{ type: string }>;

    const componentCounts: Record<string, number> = {};
    items.forEach(item => {
      if (componentTypes.has(item.type)) {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      }
    });

    let base = 0;
    for (const item of items) {
      if (componentTypes.has(item.type)) {
        const type = item.type;
        if (componentCounts[type] === 3) {
          base += 60;
          componentCounts[type] = 0;
        } else {
          base += basePremiums[type];
        }
      } else {
        base += basePremiums[item.type] || 0;
      }
    }

    return { premium: base + 5 };
  }
  return { premium: 5 };
});

console.log(JSON.stringify({ results }));

