const results = scenario.steps.map((step: any) => {
  if (step.op === "quote") {
    const items = step.items as Array<{ type: string; cursed?: boolean; enchantment?: number }>;
    const customer = scenario.customer;

    const componentCounts: Record<string, number> = {};
    items.forEach(item => {
      if (componentTypes.has(item.type)) {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      }
    });

    let base = 0;
    const usedInBlock = new Set<string>();

    for (const [type, count] of Object.entries(componentCounts)) {
      if (count === 3) {
        base += 60;
        usedInBlock.add(type);
      }
    }

    for (const item of items) {
      if (componentTypes.has(item.type)) {
        if (!usedInBlock.has(item.type)) {
          base += basePremiums[item.type];
        }
      } else {
        base += basePremiums[item.type] || 0;
      }

      if (item.cursed) {
        base += basePremiums[item.type] * 0.5;
      }
    }

    let policyBase = base;

    if (customer.yearsWithMHPCO < 2) {
      policyBase += base * 0.1;
    }

    const premium = Math.ceil(policyBase + 5);
    return { premium };
  }
  return { premium: 5 };
});

