import { describe, it, expect } from "vitest";
import { execSync } from "child_process";

const claimOffice = (input: string): string => {
  return execSync("tsx src/cli.ts", { input, encoding: "utf-8" });
};

describe("claim-office CLI", () => {
  // ============================================
  // BASE CASES
  // ============================================

  it("empty item list quote -> premium 5 G (only processing fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(5);
  });

  // ============================================
  // ITEM VALUES AND BASE PREMIUMS
  // ============================================

  it("single sword quote -> premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(115);
  });

  it("single amulet quote -> premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(71);
  });

  it("single staff quote -> premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(93);
  });

  it("single potion quote -> premium 49 G (40 base + 4 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(49);
  });

  it("single rune quote -> premium 33 G (25 base + 2.5 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(33);
  });

  it("single moonstone quote -> premium 33 G (25 base + 2.5 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "moonstone" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(33);
  });

  // ============================================
  // COMPONENT BLOCKS (3 alike components)
  // ============================================

  it("2 runes quote -> premium 60 G (2×25 base + 5 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(60);
  });

  it("3 runes quote -> premium 71 G (60 block base + 6 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(71);
  });

  it("4 runes quote -> premium 115 G (4×25 base + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(115);
  });

  it("7 runes quote -> premium 198 G (7×25 base + 17.5 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(198);
  });

  it("2 runes + 1 moonstone quote -> premium 88 G (2×25 + 25 base + 7.5 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(88);
  });

  it("3 runes + 3 moonstones quote -> premium 137 G (60 + 60 block base + 12 first insurance + 5 fee, rounded up)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }
      ] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(137);
  });

  // ============================================
  // PREMIUM MODIFIERS - Item-specific
  // ============================================

  it("cursed sword quote -> premium 165 G (100 base + 50 cursed + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(165);
  });

  it("sword with enchantment 5 quote -> premium 145 G (100 base + 30 high-enchant + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(145);
  });

  it("sword with enchantment 4 quote -> premium 115 G (no high-enchant surcharge)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(115);
  });

  it("cursed sword with enchantment 5 quote -> premium 195 G (100 base + 50 cursed + 30 high-enchant + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(195);
  });

  it("cursed sword with enchantment 4 quote -> premium 165 G (100 base + 50 cursed + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 4 }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(165);
  });

  // ============================================
  // PREMIUM MODIFIERS - Policy-wide
  // ============================================

  it("customer with 2 years loyalty quote -> premium 95 G (100 base - 20 loyalty + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(95);
  });

  it("customer with 3 years loyalty, first insurance quote -> premium 95 G (100 base - 20 loyalty + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 3 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(95);
  });

  it("customer with 3 years loyalty, second contract quote -> premium 80 G (100 base - 20 loyalty + 10 first insurance - 15 follow-up + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword" }] }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].premium).toBe(80);
  });

  // ============================================
  // MODIFIER SCOPE - Multi-item policies
  // ============================================

  it("cursed sword + plain amulet quote -> premium 231 G (100+60 base + 50 cursed on sword only + 16 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }, { type: "amulet" }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(231);
  });

  // ============================================
  // INTEGRATION EXAMPLES - Quote
  // ============================================

  it("newcomer with cursed sword (0 years, no previous) -> premium 165 G (100 + 50 cursed + 10 first insurance + 5 fee)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[0].premium).toBe(165);
  });

  it("long-standing customer's second contract with cursed sword (3 years, second quote, enchantment 7) -> premium 160 G (100 + 50 cursed + 30 high-enchant - 20 loyalty + 10 first - 15 follow-up + 5)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword", cursed: true, enchantment: 7 }] }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].premium).toBe(160);
  });

  // ============================================
  // CLAIM PROCESSING - Base cases
  // ============================================

  it("claim: regular sword damage 500 G -> payout 400 G (500 - 100 deductible)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] } }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].payout).toBe(400);
    expect(result.results[1].remainingCap).toBe(1600);
  });

  it("claim: rune damage 200 G -> payout 100 G (200 - 100 deductible)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "rune", amount: 200 }] } }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].payout).toBe(100);
    expect(result.results[1].remainingCap).toBe(400);
  });

  // ============================================
  // CLAIM PROCESSING - Special clauses
  // ============================================

  it("claim: dragon-material sword, enchantment 9, damage 1000 G -> payout 400 G (50% of 1000 = 500 - 100 deductible)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "dragon", enchantment: 9 }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1000 }] } }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].payout).toBe(400);
    expect(result.results[1].remainingCap).toBe(1600);
  });

  it("claim: dragon-material sword, enchantment 5, damage 800 G -> payout 700 G (800 - 100 deductible, full reimbursement)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "dragon", enchantment: 5 }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 800 }] } }
      ]
    });
    const output = claimOffice(input);
    const result = JSON.parse(output);
    expect(result.results[1].payout).toBe(700);
    expect(result.results[1].remainingCap).toBe(1300);
  });

  it("claim: steel sword, enchantment 9, damage 1000 G -> payout 400 G (50% of 1000 = 500 - 100 deductible)", () => {
    const input = JSON.stringify({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 9 }] },
